package org.apache.commons.lang3.builder;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.lang3.builder.steps",
    plugin = {"pretty", "html:target/cucumber-reports"}
)
public class CucumberTest {
}

package org.apache.commons.lang3.builder.steps;

import io.cucumber.java8.En;
import org.apache.commons.lang3.builder.ToStringBuilder;
import org.apache.commons.lang3.builder.ToStringStyle;

import java.lang.reflect.Field;
import java.util.Map;
import java.util.HashMap;

import static org.junit.Assert.*;

public class StepDefs implements En {

    private Object objectA;
    private Object objectB;
    private String result;

    public StepDefs() {
        // Scenario: Registry should be null after processing an object cycle
        Given("two objects \"a\" and \"b\" that reference each other forming a cycle", () -> {
            // Create two objects that reference each other
            TestObject a = new TestObject("a_identity");
            TestObject b = new TestObject("b_identity");
            a.setRef(b);
            b.setRef(a);
            objectA = a;
            objectB = b;
        });

        When("a.toString() is called using ToStringBuilder", () -> {
            result = ((TestObject) objectA).toString();
        });

        Then("the generated string should represent the cycle as \"a_identity[b_identity[a_identity]]\"", () -> {
            // Check if the result contains expected cycle representation
            assertTrue("Result should contain cycle representation", result.contains("a_identity") && result.contains("b_identity"));
            assertTrue("Result should show cycle pattern", result.contains("[a_identity]")); // Expected cycle detection
        });

        And("the ToStringStyle registry should be null", () -> {
            // Access the registry via reflection to check if it's null after processing
            try {
                Field regField = ToStringStyle.class.getDeclaredField("registry");
                regField.setAccessible(true);
                Map registry = (Map) regField.get(null);

                // After a proper toString operation, registry should be null or empty
                // If it's not null, it indicates a bug in the registry cleanup mechanism
                if (registry != null && !registry.isEmpty()) {
                    fail("Registry should be null or empty after processing but contains: " + registry.size() + " elements");
                }

                // For this bug test, we expect it to fail because the registry isn't being cleaned up properly
                // The bug in Lang-34 is that the registry remains populated with ThreadLocal references
            } catch (Exception e) {
                // If we can't access the registry via reflection, we can't test the requirement
                fail("Could not access registry field: " + e.getMessage());
            }
        });
    }

    private static class TestObject {
        private String id;
        private TestObject ref;

        public TestObject(String id) {
            this.id = id;
        }

        public void setRef(TestObject ref) {
            this.ref = ref;
        }

        @Override
        public String toString() {
            return new ToStringBuilder(this).append("id", id).append("ref", ref).toString();
        }

        public String getId() {
            return id;
        }
    }
}

